import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 法輪 } from '../bujian/sanmaya.js';
import { 側拳, 臂釧, 腕釧 } from '../bujian/index.js';
export const 金剛因 = (bi) => 菩薩坐身(bi, {
    臂(bi, 筆) {
        const { M, Qk, S, 骨, 衣, 細, 陰, 陽 } = 筆;
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.2); });
        // 尊右：前臂上舉，仰掌擎輪於胸前
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.1], [-7.7, 40.0], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.4, 肘帽: true })));
        衣(() => {
            // 仰掌淺盂
            M(-11.0, 39.7);
            Qk(-8.9, 40.7, -6.8, 40.0);
            S();
            M(-10.7, 40.4);
            Qk(-8.9, 41.2, -7.2, 40.6);
            S();
            細(() => {
                for (const t of [0, 1, 2]) {
                    M(-10.5 + t * 1.15, 39.45 - t * 0.1);
                    Qk(-10.2 + t * 1.15, 39.1 - t * 0.1, -9.8 + t * 1.15, 38.95 - t * 0.1);
                    S();
                }
            });
        });
        法輪(bi, -8.9, 35.6, 0.85);
        // 尊左：前臂垂，拳安腰際
        骨(() => 陰(() => 前臂(bi, 筆, [13.8, 40.3], [13.0, 45.6], { 寬根: 2.4, 寬梢: 1.8, 弓: -0.3, 肘帽: false })));
        側拳(bi, 12.8, 47.9, Math.PI / 2, 1.05, -1);
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-12.0, 38.7, -11.2, 39.6, -10.4, 40.4], [-11.5, 38.1, -10.7, 39.0, -9.9, 39.8]], [-11.0, 39.1]);
            腕釧(bi, [[11.9, 44.9, 13.0, 45.4, 14.1, 45.0], [11.8, 45.8, 12.9, 46.3, 14.0, 45.9]], [12.9, 45.8]);
        });
    },
});
